const API_BASE_URL = 'http://localhost:8080'

// 过滤敏感字段的函数
function filterSensitiveFields(data) {
  if (data === null || typeof data !== 'object') {
    return data
  }

  if (Array.isArray(data)) {
    return data.map(item => filterSensitiveFields(item))
  }

  const filtered = { ...data }

  // 过滤密码字段
  if (filtered.password) {
    delete filtered.password
  }

  // 过滤嵌套对象中的密码字段
  if (filtered.user && typeof filtered.user === 'object') {
    if (filtered.user.password) {
      delete filtered.user.password
    }
  }

  // 递归处理其他嵌套对象
  Object.keys(filtered).forEach(key => {
    if (typeof filtered[key] === 'object' && filtered[key] !== null) {
      filtered[key] = filterSensitiveFields(filtered[key])
    }
  })

  return filtered
}

export const request = {
  async post(url, data) {
    try {
      const response = await fetch(`${API_BASE_URL}${url}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(data),
        credentials: 'include'
      })
      const result = await response.json()
      return filterSensitiveFields(result)
    } catch (error) {
      console.error('请求失败:', error)
      return { success: false, message: '网络请求失败' }
    }
  },

  async get(url, params) {
    try {
      let queryString = ''
      if (params) {
        queryString = '?' + Object.keys(params).map(key => `${key}=${params[key]}`).join('&')
      }
      const response = await fetch(`${API_BASE_URL}${url}${queryString}`, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json'
        },
        credentials: 'include'
      })
      const result = await response.json()
      return filterSensitiveFields(result)
    } catch (error) {
      console.error('请求失败:', error)
      return { success: false, message: '网络请求失败' }
    }
  },

  async put(url, data) {
    try {
      const response = await fetch(`${API_BASE_URL}${url}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(data),
        credentials: 'include'
      })
      const result = await response.json()
      return filterSensitiveFields(result)
    } catch (error) {
      console.error('请求失败:', error)
      return { success: false, message: '网络请求失败' }
    }
  },

  async delete(url) {
    try {
      const response = await fetch(`${API_BASE_URL}${url}`, {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json'
        },
        credentials: 'include'
      })
      const result = await response.json()
      return filterSensitiveFields(result)
    } catch (error) {
      console.error('请求失败:', error)
      return { success: false, message: '网络请求失败' }
    }
  }
}

export default request
